+    if let Ok(seq) = keys_bound.try_iter() {
+        // Tuple/list input: each element is an array-like.
+        let first_shape: Option<Vec<usize>> = None;
+        let mut first_shape = first_shape;
+        let mut collected_via_iter = false;
+        for item in seq {
+            let item = item?;
