+                return fallback(py);
+            }
+            if let Some(shape) = first_shape.as_ref() {
+                if shape != native.shape() {
+                    return fallback(py);
+                }
+            } else {
+                first_shape = Some(native.shape().to_vec());
+            }
+            key_arrays.push(native);
+            collected_via_iter = true;
+        }
+        if !collected_via_iter {
+            return fallback(py);
+        }
